import org.junit.Assert.assertEquals
import org.junit.Test
import com.ichi2.libanki.parseSourcesToFileScheme

class BugReproductionTest {

    @Test
    fun `parseSourcesToFileScheme - mixed script`() {
        val input = """
            <!-- VERSION 1.14 -->
            <script>
            var scrollToClozeOnToggle = false
            </script>
            <div id="extra-section">
            <img src="foo.jpg">
            </div>
        """.trimIndent()
        val result = parseSourcesToFileScheme(input, "/storage/emulated/0/15773/collection.media")
        assert(result.contains("var scrollToClozeOnToggle = false")) { "Script tag lost!" }
        assert(result.contains("<img src=\"file:///storage/emulated/0/15773/collection.media/foo.jpg\">"))
    }

    @Test
    fun `parseSourcesToFileScheme - preserve body class`() {
        val input = """
            <body class="my-class">
            <img src="foo.jpg">
            </body>
        """.trimIndent()
        val result = parseSourcesToFileScheme(input, "/storage/emulated/0/15773/collection.media")
        assert(result.contains("class=\"my-class\"")) { "Body class lost!" }
    }
}
"}

